module watchdog_timer(  
    input wire clk,  
    input wire update,  
    input wire [3:0] timeout,  
    output reg reset  
);  
    reg [3:0] obf_counter;  

    always @(posedge clk) begin  
        if (update)  
            obf_counter <= timeout;  
        else if (obf_counter > 0)  
            obf_counter <= obf_counter - 1;  

        reset <= (obf_counter == 0);  
    end  
endmodule
